@namespace Lumeo
@implements IAsyncDisposable

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<div class="w-full">
    <textarea @ref="_textareaRef"
              id="@EffectiveId"
              name="@Name"
              aria-required="@Required.ToString().ToLowerInvariant()"
              aria-invalid="@((EffectiveInvalid || IsOverLimit).ToString().ToLowerInvariant())"
              aria-describedby="@FormFieldDescribedBy"
              class="@CssClass" value="@Value" @oninput="HandleInput" disabled="@Disabled"
              maxlength="@EffectiveMaxLength" @attributes="EffectiveAttributes"></textarea>
    @if (ShowCount)
    {
        <div class="mt-1 text-xs @CountClass text-end">
            @(Value?.Length ?? 0)@(MaxLength.HasValue ? $"/{MaxLength}" : "")
        </div>
    }
</div>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && !string.IsNullOrEmpty(ErrorText))
    {
        <p class="mt-1 text-xs text-destructive" role="alert" aria-live="polite">@ErrorText</p>
    }
    else if (!string.IsNullOrEmpty(HelperText))
    {
        <p class="mt-1 text-xs text-muted-foreground">@HelperText</p>
    }
}
</div>

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }
    [Parameter] public EventCallback<ChangeEventArgs> OnInput { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool AutoResize { get; set; }
    [Parameter] public int MaxRows { get; set; } = 10;
    [Parameter] public bool ShowCount { get; set; }
    [Parameter] public int? MaxLength { get; set; }
    [Parameter] public TextareaResize Resize { get; set; } = TextareaResize.Vertical;
    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }
    /// <summary>Per-textarea density override. When null, inherits from any
    /// ancestor <see cref="DensityScope"/>; if neither is set, matches the
    /// historical <c>Comfortable</c> default. Only padding / min-height
    /// shifts between values.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    /// <summary>Focuses the underlying &lt;textarea&gt; on first render. See
    /// Input.AutoFocus — the HTML autofocus attribute doesn't work in Blazor
    /// WASM because parse-time has already passed by the time the runtime
    /// adds the element to the DOM.</summary>
    [Parameter] public bool AutoFocus { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _elementId = LumeoIds.New("textarea");
    private bool _autoResizeSetup;
    // Last Value / MaxRows that auto-resize was (re-)measured against. Tracked so a
    // programmatic Value change (which fires no DOM 'input' event) or a runtime
    // MaxRows change triggers a fresh measure instead of leaving a stale height.
    private string? _autoResizeValue;
    private int _autoResizeMaxRows;
    private ElementReference _textareaRef;

    /// <summary>The underlying &lt;textarea&gt; element.</summary>
    public ElementReference Element => _textareaRef;

    /// <summary>Programmatically move focus to the textarea.</summary>
    public ValueTask FocusAsync() => _textareaRef.FocusAsync();

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Point aria-describedby at the FormField's rendered help/error text so a screen
    // reader announces it on this textarea (null outside a FormField).
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Inside a FormField, adopt its generated ControlId so the field's <Label For>
    // resolves to this textarea (click-to-focus + association). Null outside a
    // FormField — EffectiveId then falls back to the generated _elementId. The
    // empty guard avoids id="" when no id was generated.
    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;

    // The id actually rendered on the <textarea>. The auto-resize JS interop
    // (SetupAutoResize / UnregisterAutoResize) MUST key off this same value so the
    // registered element id matches the rendered id — otherwise auto-resize can't
    // find the element. _elementId stays as the fallback.
    private string EffectiveId => FormFieldControlId ?? _elementId;

    // Inside a FormField the generated EffectiveId must own the <textarea id> so the
    // field's <Label For> and the auto-resize JS (keyed off EffectiveId) stay in sync.
    // A consumer-splatted id in AdditionalAttributes renders after the explicit id= and
    // would override it, so strip it here. Outside a FormField the bag passes through.
    private Dictionary<string, object>? EffectiveAttributes =>
        InsideFormField && AdditionalAttributes?.ContainsKey("id") == true
            ? AdditionalAttributes.Where(kv => kv.Key != "id").ToDictionary(kv => kv.Key, kv => kv.Value)
            : AdditionalAttributes;

    private string ResizeClass => Resize switch
    {
        TextareaResize.Vertical => "resize-y",
        TextareaResize.Horizontal => "resize-x",
        TextareaResize.Both => "resize",
        TextareaResize.None => "resize-none",
        _ => "resize-y"
    };

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    // Only the min-height floor + body padding shift with density; text size
    // and radius stay fixed (governed elsewhere). Comfortable reproduces the
    // historical `min-h-[60px] px-3 py-2` verbatim.
    private string SizeClasses => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "min-h-[48px] px-2.5 py-1.5",
        Lumeo.Density.Spacious => "min-h-[80px] px-4 py-3",
        _ => "min-h-[60px] px-3 py-2"
    };

    private string CssClass => Cx.Merge("flex", SizeClasses, "w-full rounded-md border", (EffectiveInvalid ? "border-destructive" : "border-input"), "bg-transparent text-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px]", (EffectiveInvalid ? "focus-visible:ring-destructive/20" : "focus-visible:ring-ring"), "disabled:cursor-not-allowed disabled:opacity-50", ResizeClass, Class);

    private bool IsOverLimit => MaxLength.HasValue && (Value?.Length ?? 0) > MaxLength.Value;

    // When a character counter is shown we deliberately DROP the native maxlength
    // hard-cap so the field behaves as a soft limit (matching AntD/shadcn): the
    // user can type past the limit and the counter turns red to warn them. With a
    // hard maxlength the browser silently blocks the extra characters, so the
    // over-limit warning state (and CountClass) could never be reached. Without a
    // counter we keep the hard cap as a plain input constraint.
    private int? EffectiveMaxLength => ShowCount ? null : MaxLength;

    private string CountClass => IsOverLimit ? "text-destructive" : "text-muted-foreground";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (AutoResize && !_autoResizeSetup)
        {
            // Reconcile every render, not only firstRender (#166): toggling
            // AutoResize false->true AFTER the first render must still wire up the
            // measure. Latching on firstRender meant a runtime opt-in never
            // registered.
            await Interop.SetupAutoResize(EffectiveId, MaxRows);
            _autoResizeSetup = true;
            _autoResizeValue = Value;
            _autoResizeMaxRows = MaxRows;
        }
        else if (!AutoResize && _autoResizeSetup)
        {
            // Toggling AutoResize true->false must tear the measure down (#166),
            // otherwise the JS input listener leaks and keeps resizing a field the
            // consumer has opted out of.
            await Interop.UnregisterAutoResize(EffectiveId);
            _autoResizeSetup = false;
        }
        else if (_autoResizeSetup && AutoResize && (Value != _autoResizeValue || MaxRows != _autoResizeMaxRows))
        {
            // The textarea only auto-resizes on its own 'input' event, so a Value
            // set programmatically (#67) leaves the height stale, and a runtime
            // MaxRows change (#167) leaves the cap stale. Re-running setupAutoResize
            // re-measures immediately and updates the captured maxHeight; the JS
            // de-dupes the prior input listener, so re-calling never stacks handlers.
            await Interop.SetupAutoResize(EffectiveId, MaxRows);
            _autoResizeValue = Value;
            _autoResizeMaxRows = MaxRows;
        }
        if (firstRender && AutoFocus)
        {
            try { await _textareaRef.FocusAsync(); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (!_autoResizeSetup) return;
        try { await Interop.UnregisterAutoResize(EffectiveId); }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
    }

    private async Task HandleInput(ChangeEventArgs e)
    {
        Value = e.Value?.ToString();
        // A user keystroke already triggered the JS 'input' listener's resize(),
        // so the height is current — record it so the OnAfterRender remeasure does
        // not redundantly re-run setupAutoResize on every keystroke. The remeasure
        // is reserved for Value changes that arrive WITHOUT a DOM input event (#67).
        _autoResizeValue = Value;
        await OnInput.InvokeAsync(e);
        await ValueChanged.InvokeAsync(Value);
    }

    public enum TextareaResize
    {
        Vertical,
        Horizontal,
        Both,
        None
    }
}
